const App = () => {
  const course = 'Half Stack application development'
  const part1 = {
    name: 'Fundamentals of React',
    exercises: 10
  }
  const part2 = {
    name: 'Using props to pass data',
    exercises: 7
  }
  const part3 = {
    name: 'State of a component',
    exercises: 14
  }
  const exercises1 = 10
  const exercises2 = 7
  const exercises3 = 14
  return (
    <div>
      <Header course={course} />
      <Content contentProps={parts.part} />
      <Total exercises1={exercises1} exercises2={exercises2} exercises3={exercises3} />
    </div>
  )
}
const Header = (props) => {
  console.log(props)
  return (
    <h1>{props.course}</h1>
  )
}
const ContentMix = (props) => {
  return (
    <p>
      {props.part.name} {props.part.exercise}
    </p>
  )
}
const Content = (props) => {
  return (
    <>
      <ContentMix part={props.contentProps[0]} />
      <ContentMix part={props.contentProps[1]} />
      <ContentMix part={props.contentProps[2]} />
    </>
  )
}
const Total = (props) => {
  return (
    <p>Number of exercises{" "}
      {props.exercises1 + props.exercises2 + props.exercises3}
    </p>
  )
}
export default App
